   case Intrinsic::vector_reduce_xor: {
@@ -3760,6 +3761,66 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         if (Instruction *R = FoldOpIntoSelect(*II, Sel))
           return R;

+  // Handle scalar umax/umin optimizations
+  if (IID == Intrinsic::umax || IID == Intrinsic::umin) {
+    Value *LHS = II->getArgOperand(0);
+    Value *RHS = II->getArgOperand(1);
+    Value *X;
+    
+    // Pattern: umax(2*X, X+1) -> X == 0 ? X+1 : 2*X
+    // Pattern: umin(2*X, X+1) -> X == 0 ? 2*X : X+1
+    // Handle both operand orders
+    auto MatchPattern = [&](Value *A, Value *B) -> bool {
+      Value *ShlX, *AddX;
+      // Check if A is shl nuw X, 1 and B is add X, 1
+      if (match(A, m_NUWShl(m_Value(ShlX), m_One())) &&
+          match(B, m_Add(m_Value(AddX), m_One())) &&
+          ShlX == AddX) {
+        X = ShlX;
+        return true;
+      }
+      return false;
+    };
+    
+    bool Matched = MatchPattern(LHS, RHS);
+    if (!Matched) {
+      Matched = MatchPattern(RHS, LHS);
+      if (Matched) {
+        // Swap operands to maintain consistent ordering
+        std::swap(LHS, RHS);
+      }
+    }
+    
+    if (Matched) {
+      // Create comparison X == 0
+      Value *IsZero = Builder.CreateICmpEQ(X, ConstantInt::get(X->getType(), 0));
+      
+      // Identify which operand is add and which is shl
+      Value *AddVal = nullptr;
+      Value *ShlVal = nullptr;
+      
+      if (match(LHS, m_Add(m_Specific(X), m_One())) &&
+          match(RHS, m_NUWShl(m_Specific(X), m_One()))) {
+        AddVal = LHS;
+        ShlVal = RHS;
+      } else if (match(RHS, m_Add(m_Specific(X), m_One())) &&
+                 match(LHS, m_NUWShl(m_Specific(X), m_One()))) {
+        AddVal = RHS;
+        ShlVal = LHS;
+      }
+      
+      if (AddVal && ShlVal) {
+        // For umax: select IsZero, X+1, 2*X
+        // For umin: select IsZero, 2*X, X+1
+        Value *TrueVal = (IID == Intrinsic::umax) ? AddVal : ShlVal;
+        Value *FalseVal = (IID == Intrinsic::umax) ? ShlVal : AddVal;
+        
+        Value *Sel = Builder.CreateSelect(IsZero, TrueVal, FalseVal);
+        return replaceInstUsesWith(CI, Sel);
+      }
+    }
+  }
+
   if (Instruction *Shuf = foldShuffledIntrinsicOperands(II, Builder))
     return Shuf;

@@ -3768,6 +3829,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
